arguments.file_text:
@* Step indicator bar showing progress through the multi-step form *@

<nav class="step-indicator" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var isCurrent = step == CurrentStep;
        var isCompleted = step < CurrentStep;
        var isFuture = step > CurrentStep;

        <button type="button"
                class="step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                disabled="@isFuture"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(isCurrent ? "step" : null)">
            <span class="step-number">
                @if (isCompleted)
                {
                    <span aria-hidden="true">✓</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (step < StepNames.Length - 1)
        {
            <span class="step-connector @(step < CurrentStep ? "completed" : "")" aria-hidden="true"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@* A single work-experience entry form card *@

<div class="work-entry-card">
    <div class="card-header">
        <h4>Position @(Index + 1)</h4>
        @if (ShowRemove)
        {
            <button type="button" class="btn-remove" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company Name *</label>
        <input type="text" @bind="Entry.Company" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" @bind="Entry.Title" @bind:event="oninput" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" @bind="Entry.StartDate" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            <label class="checkbox-label">
                <input type="checkbox" @bind="Entry.IsCurrent" @bind:after="ClearEndDate" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" @bind="Entry.Description" @bind:event="oninput"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private void ClearEndDate()
    {
        if (Entry.IsCurrent)
            Entry.EndDate = null;
    }
}

@* Step 1 — Personal information form *@

<div class="step-content">
    <h3>Personal Information</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-banner">@ErrorMessage</div>
    }

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" @bind="Personal.FullName" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label>Email *</label>
        <input type="email" @bind="Personal.Email" @bind:event="oninput" />
        @if (!string.IsNullOrEmpty(emailError))
        {
            <span class="field-error">@emailError</span>
        }
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Phone *</label>
            <input type="tel" @bind="Personal.Phone" @bind:event="oninput" />
        </div>

        <div class="form-group">
            <label>Address *</label>
            <input type="text" @bind="Personal.Address" @bind:event="oninput" />
        </div>
    </div>

    <div class="step-actions">
        <button type="button" class="btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @(isValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? ErrorMessage;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;
        emailError = null;

        if (string.IsNullOrWhiteSpace(Personal.FullName) ||
            string.IsNullOrWhiteSpace(Personal.Email) ||
            string.IsNullOrWhiteSpace(Personal.Phone) ||
            string.IsNullOrWhiteSpace(Personal.Address))
        {
            ErrorMessage = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var isEmailValid = await ApplicationService.ValidateEmailAsync(Personal.Email);
            if (!isEmailValid)
            {
                emailError = "This email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@* Step 2 — Work history with dynamic entries *@

<div class="step-content">
    <h3>Work History</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-banner">@ErrorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryCard Entry="Entries[index]"
                       Index="index"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    <div class="step-actions">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                ErrorMessage = "Please fill in company, title, and start date for every position.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@* Step 3 — References (2–3 entries) *@

<div class="step-content">
    <h3>References</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-banner">@ErrorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceCard Reference="References[index]"
                       Index="index"
                       ShowRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    <div class="step-actions">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
