@* Step indicator bar showing progress through the multi-step form *@

<nav class="step-indicator" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var isCurrent = step == CurrentStep;
        var isCompleted = step < CurrentStep;
        var isFuture = step > CurrentStep;

        <button type="button"
                class="step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                disabled="@isFuture"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(isCurrent ? "step" : null)">
            <span class="step-number">
                @if (isCompleted)
                {
                    <span aria-hidden="true">✓</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (step < StepNames.Length - 1)
        {
            <span class="step-connector @(step < CurrentStep ? "completed" : "")" aria-hidden="true"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

