            <label>Start Date *</label>
            <input type="date" @bind="Entry.StartDate" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            <label class="checkbox-label">
                <input type="checkbox" @bind="Entry.IsCurrent" @bind:after="ClearEndDate" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" @bind="Entry.Description" @bind:event="oninput"></textarea>
