@* Step 4 — Cover letter with character count *@

<div class="step-content">
    <h3>Cover Letter</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-banner">@ErrorMessage</div>
    }

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea rows="12" maxlength="@MaxLength"
                  @bind="CoverLetter" @bind:event="oninput"
                  @bind:after="NotifyChanged"></textarea>
        <span class="char-count @(CoverLetter.Length > MaxLength ? "over-limit" : "")">
            @CoverLetter.Length / @MaxLength characters
        </span>
    </div>

    <div class="step-actions">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task NotifyChanged() => await CoverLetterChanged.InvokeAsync(CoverLetter);

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "Please write a cover letter before proceeding.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

