toolArgs.file_text:
@* Step 5 — Review all data and submit *@

<div class="step-content">
    <h3>Review &amp; Submit</h3>

    @if (IsSubmitted)
    {
        <div class="success-banner">
            <h4>🎉 Application Submitted!</h4>
            <p>Your application has been received. Your confirmation number is <strong>#@ApplicationId</strong>.</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="error-banner">@ErrorMessage</div>
        }

        @* Personal Info *@
        <section class="review-section">
            <div class="review-header">
                <h4>Personal Information</h4>
                <button type="button" class="btn-link" @onclick='() => OnEditStep.InvokeAsync(0)'>Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        @* Work History *@
        <section class="review-section">
            <div class="review-header">
                <h4>Work History</h4>
                <button type="button" class="btn-link" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="date-range">
                        @entry.StartDate?.ToString("MMM yyyy")
                        – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </section>

        @* References *@
        <section class="review-section">
            <div class="review-header">
                <h4>References</h4>
                <button type="button" class="btn-link" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-entry">
                    <strong>@r.Name</strong> — @r.Relationship
                    <br />@r.Email @(!string.IsNullOrWhiteSpace(r.Phone) ? $"| {r.Phone}" : "")
                </div>
            }
        </section>

        @* Cover Letter *@
        <section class="review-section">
            <div class="review-header">
                <h4>Cover Letter</h4>
                <button type="button" class="btn-link" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </section>

        <div class="step-actions">
            <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
            <button type="button" class="btn-primary btn-submit" @onclick="HandleSubmit" disabled="@isSubmitting">
                @(isSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback<int> OnSubmitted { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private bool isSubmitting;
    private bool IsSubmitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        ErrorMessage = null;

        try
        {
            var application = new JobApplication(
                new PersonalInfo(Personal.FullName, Personal.Email, Personal.Phone, Personal.Address),
                new WorkHistory(WorkEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate!.Value,
                    e.IsCurrent ? null : e.EndDate,
                    e.Description)).ToList()),
                References.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                CoverLetter
            );

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
            await OnSubmitted.InvokeAsync(ApplicationId);
        }
        catch (Exception)
        {
            ErrorMessage = "Something went wrong while submitting your application. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

