    padding: 0.5rem 0.75rem;
    min-width: 6rem;
}

.step-indicator .step.future {
    cursor: default;
    opacity: 0.45;
}

.step-number {
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    display: flex;
    align-items: center;
