    color: #64748b;
    background: #fff;
    transition: all 0.2s;
}

.step.current .step-number {
    border-color: #2563eb;
    background: #2563eb;
    color: #fff;
}

.step.completed .step-number {
    border-color: #16a34a;
    background: #16a34a;
    color: #fff;
}

.step-label {
    font-size: 0.75rem;
    color: #64748b;
    text-align: center;
    white-space: nowrap;
}

.step.current .step-label {
    color: #2563eb;
    font-weight: 600;
}

.step.completed .step-label {
    color: #16a34a;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background: #cbd5e1;
    align-self: center;
    margin-bottom: 1.2rem;
}

.step-connector.completed {
    background: #16a34a;
}

