}

.btn-primary {
    background: #2563eb;
    color: #fff;
    border: none;
    padding: 0.6rem 1.5rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-primary:hover:not(:disabled) {
    background: #1d4ed8;
}

.btn-primary:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-outline {
    background: #fff;
    color: #334155;
    border: 1px solid #cbd5e1;
    padding: 0.6rem 1.5rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-outline:hover {
    background: #f1f5f9;
}

.btn-secondary {
    background: none;
    border: 1px dashed #94a3b8;
    color: #475569;
    padding: 0.5rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.85rem;
    cursor: pointer;
    margin-bottom: 0.5rem;
    transition: background 0.15s;
}

.btn-secondary:hover {
    background: #f1f5f9;
}

.btn-remove {
    background: none;
    border: none;
    color: #dc2626;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 0.25rem 0.5rem;
}

.btn-remove:hover {
    text-decoration: underline;
}

.btn-link {
    background: none;
    border: none;
    color: #2563eb;
    cursor: pointer;
    font-size: 0.85rem;
    padding: 0;
    text-decoration: underline;
}

.btn-submit {
    padding: 0.75rem 2rem;
    font-size: 1rem;
}

/* ---- Character count ---- */
.char-count {
    display: block;
    text-align: right;
    font-size: 0.8rem;
    color: #64748b;
    margin-top: 0.3rem;
}

.char-count.over-limit {
    color: #dc2626;
    font-weight: 600;
}

/* ---- Validation / banners ---- */
.error-banner {
    background: #fef2f2;
    color: #991b1b;
    border: 1px solid #fecaca;
    border-radius: 0.375rem;
    padding: 0.75rem 1rem;
    margin-bottom: 1rem;
    font-size: 0.875rem;
}

.field-error {
    color: #dc2626;
    font-size: 0.8rem;
    margin-top: 0.2rem;
    display: block;
}

.success-banner {
    background: #f0fdf4;
    color: #166534;
    border: 1px solid #bbf7d0;
    border-radius: 0.5rem;
    padding: 1.5rem;
    text-align: center;
}

.success-banner h4 {
    margin-top: 0;
    font-size: 1.25rem;
}

/* ---- Review sections ---- */
.review-section {
    border: 1px solid #e2e8f0;
    border-radius: 0.375rem;
    padding: 1rem 1.25rem;
    margin-bottom: 1rem;
}

.review-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.review-header h4 {
    margin: 0;
    font-size: 1rem;
}

.review-section dl {
    display: grid;
    grid-template-columns: 8rem 1fr;
    gap: 0.3rem 1rem;
    margin: 0;
    font-size: 0.9rem;
}

.review-section dt {
    color: #64748b;
    font-weight: 500;
}

.review-section dd {
    margin: 0;
    color: #1e293b;
}

.review-entry {
    padding: 0.5rem 0;
    font-size: 0.9rem;
    border-bottom: 1px solid #f1f5f9;
}

.review-entry:last-child {
    border-bottom: none;
}

.date-range {
    font-size: 0.8rem;
    color: #64748b;
}

.cover-letter-preview {
    white-space: pre-wrap;
    font-size: 0.9rem;
    color: #334155;
    background: #f8fafc;
    padding: 0.75rem;
    border-radius: 0.25rem;
}

/* ---- Responsive ---- */
@media (max-width: 640px) {
    .form-row {
        grid-template-columns: 1fr;
    }

    .step-indicator .step {
        min-width: 4rem;
        padding: 0.3rem;
    }

    .step-label {
        font-size: 0.65rem;
    }
}

